package com.netflix.governator.configuration;

import com.netflix.governator.configuration.Property;
import javax.xml.bind.DatatypeConverter;
import java.text.DateFormat;
import java.text.ParseException;
import java.util.Date;
import java.util.Locale;


public class DateWithDefaultProperty extends Property<Date>
{
    private final Date defaultValue;
    private final Property<String> supplier;
    private final DateFormat formatter;

    public DateWithDefaultProperty(Property<String> supplier, Date defaultValue)
    {
        this.defaultValue = defaultValue;
        this.supplier = supplier;

        formatter = DateFormat.getDateInstance(DateFormat.SHORT, Locale.getDefault());
        formatter.setLenient(false);
    }

    @Override
    public Date get()
    {
        String current = supplier.get();
        if ( current != null )
        {
            Date newDate = parseDate(current);
            if ( newDate != null )
            {
                return newDate;
            }
        }
        return defaultValue;
    }

    private Date parseDate(String value)
    {
        if ( value == null )
        {
            return null;
        }

        try
        {
            return formatter.parse(value);
        }
        catch ( ParseException e )
        {

        }

        try
        {
            return DatatypeConverter.parseDateTime(value).getTime();
        }
        catch ( IllegalArgumentException e )
        {

        }

        return null;
    }
}
